#!/bin/bash
#
# Drive a batch of the AMDGPU default-subtarget pinning migration for
# autogenerated tests.
#
# For each listed test this:
#   1. pins the default subtarget on bare llc RUN lines
#      (amdgpu-pin-default-subtarget.py: amdhsa -> gfx700, else gfx600),
#   2. regenerates the autogenerated CHECK lines with the appropriate
#      update_*_test_checks.py (chosen from the file's header),
#   3. runs llvm-lit and reverts any file that still fails, so only clean,
#      regenerated migrations remain staged.
#
# Pinning the default subtarget changes codegen (e_flags, scheduling, kernel
# descriptor), which is why the CHECK lines must be regenerated rather than
# preserved. Only run this on autogenerated tests; hand-written tests need
# manual updates.
#
# Usage:
#   amdgpu-pin-default-subtarget-batch.sh <list-file> [build-dir]
set -u
HERE="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PIN="$HERE/amdgpu-pin-default-subtarget.py"
LIST="${1:?usage: $0 <list-file> [build-dir]}"
BUILD="${2:-build_rel_with_debinfo}"
LIT="$BUILD/bin/llvm-lit"
LLC="$BUILD/bin/llc"

NCAND=$(grep -c . "$LIST")
echo "batch: $NCAND candidate files"

# 1. Pin. Prints each changed file.
xargs "$PIN" < "$LIST" > /tmp/pin_changed.txt
NCHANGED=$(grep -c . /tmp/pin_changed.txt)
echo "pinned: $NCHANGED files"
[ "$NCHANGED" -eq 0 ] && { echo "nothing to do"; exit 0; }

# 2. Regenerate, dispatching on the autogenerated-by header.
while IFS= read -r f; do
  [ -z "$f" ] && continue
  hdr=$(head -1 "$f")
  case "$hdr" in
    *update_llc_test_checks.py*) "$HERE/update_llc_test_checks.py" --llc-binary "$LLC" "$f" ;;
    *update_mir_test_checks.py*) "$HERE/update_mir_test_checks.py" --llc-binary "$LLC" "$f" ;;
    *update_test_checks.py*)     "$HERE/update_test_checks.py" "$f" ;;
    *update_givaluetracking_test_checks.py*) "$HERE/update_givaluetracking_test_checks.py" --llc-binary "$LLC" "$f" ;;
    *) echo "WARN: unknown update script for $f" ;;
  esac
done < /tmp/pin_changed.txt

# 3. Lit, revert failures.
xargs "$LIT" -q < /tmp/pin_changed.txt > /tmp/pin_lit.txt 2>&1
echo "lit summary:"; grep -E 'Total Discovered|Passed|Failed|Unsupported|Unresolved' /tmp/pin_lit.txt

grep -E '^[[:space:]]+LLVM :: ' /tmp/pin_lit.txt \
  | sed -E 's#^[[:space:]]+LLVM :: #llvm/test/#; s/ \(.*\)$//' \
  | sort -u > /tmp/pin_failed.txt
NFAIL=$(grep -c . /tmp/pin_failed.txt)
echo "failed: $NFAIL files (reverting)"
if [ "$NFAIL" -gt 0 ]; then
  cat /tmp/pin_failed.txt
  xargs git checkout -- < /tmp/pin_failed.txt
fi
echo "kept: $(( NCHANGED - NFAIL )) migrated files staged"
